import type { RtEncyclopediaEntry } from "./respiratory-therapy-encyclopedia-data";

export const RT_ENCYCLOPEDIA_FINAL: RtEncyclopediaEntry[] = [

  // ═══ Mechanical Ventilation (5 more) ═══
  {slug:"airway-pressure-release-ventilation",title:"Airway Pressure Release Ventilation (APRV)",category:"Mechanical Ventilation",seoTitle:"APRV – Airway Pressure Release Ventilation | RRT Encyclopedia",seoDescription:"Learn APRV: inverse-ratio pressure ventilation, settings (Phigh, Plow, Thigh, Tlow), indications, and management for the RRT exam.",seoKeywords:["APRV","airway pressure release ventilation","inverse ratio","Phigh","Thigh","Tlow","open lung","RRT exam"],overview:"APRV is a pressure-controlled, time-cycled mode that maintains a prolonged high airway pressure (Phigh) to recruit and keep alveoli open, with brief intermittent releases to a low pressure (Plow) for CO2 elimination. It is essentially CPAP with periodic brief releases. Patients can breathe spontaneously at both pressure levels, preserving diaphragmatic function.",mechanismPhysiology:"APRV applies a high continuous pressure (Phigh, typically 20–30 cmH2O) for a prolonged time (Thigh, typically 4–6 seconds) to maintain alveolar recruitment. Brief releases to Plow (typically 0 cmH2O) for a short time (Tlow, typically 0.5–0.8 seconds) allow passive exhalation for CO2 removal. The release time is set to terminate at 75% of peak expiratory flow rate (PEFR) to prevent derecruitment. Spontaneous breathing during Phigh improves V/Q matching, recruits dependent lung, and reduces sedation needs.",clinicalRelevance:"APRV is used as an open-lung strategy in ARDS and acute lung injury. Advantages: maintains alveolar recruitment, allows spontaneous breathing (less sedation), may improve hemodynamics (negative intrathoracic pressure during spontaneous breaths improves venous return). Controversy: limited high-quality RCT evidence comparing APRV to conventional lung-protective ventilation. May be difficult to ensure lung-protective tidal volumes during releases.",signsSymptoms:"Indications: ARDS with refractory hypoxemia, patients requiring high PEEP/MAP on conventional ventilation, desire to allow spontaneous breathing. Contraindications: severe obstructive disease (air trapping risk), hemodynamic instability, patient unable to sustain spontaneous breathing efforts.",assessment:"Monitor: Vt during releases (should approximate 6 mL/kg IBW), spontaneous Vt, total minute ventilation, PEFR during releases (Tlow should terminate at 75% of PEFR), auto-PEEP (desirable — ~5 cmH2O from incomplete exhalation preserves recruitment), ABG response. CXR for lung expansion.",management:"Initial settings: Phigh = previous Pplat or MAP + 2–4, Plow = 0 (rely on short Tlow for auto-PEEP), Thigh = 4–6 seconds, Tlow = 0.5–0.8 seconds (adjust to terminate at 75% PEFR), FiO2 to target SpO2. Weaning: progressively reduce Phigh and increase Thigh ('drop and stretch') until Phigh approximates CPAP level, then convert to CPAP/PSV.",complications:"Overdistension if Phigh too high, derecruitment if Tlow too long, air trapping in obstructive disease, hemodynamic effects of sustained high MAP, difficulty monitoring lung-protective parameters.",clinicalPearls:["Tlow should be set to terminate at 75% of peak expiratory flow rate — this prevents complete exhalation and derecruitment","Plow is typically set to 0 cmH2O — the short Tlow creates auto-PEEP that maintains recruitment","Spontaneous breathing during APRV is desirable — it improves V/Q matching and reduces sedation","APRV weaning is called 'drop and stretch' — gradually reduce Phigh and increase Thigh"],examPitfalls:["Setting Tlow too long — allows complete exhalation and derecruitment","Not monitoring release Vt — should approximate 6 mL/kg IBW for lung protection","Thinking Plow = PEEP — in APRV, auto-PEEP from short Tlow provides the actual end-expiratory pressure","Using APRV in severe COPD/asthma — air trapping can be dangerous"],faqJson:[{question:"How is CO2 cleared in APRV?",answer:"CO2 is eliminated during the brief releases from Phigh to Plow. The release volume (similar to a tidal volume) removes CO2. Adjusting Tlow changes the release volume, and changing the number of releases per minute (via Thigh) adjusts minute ventilation."},{question:"What is the 'drop and stretch' weaning method?",answer:"Gradually decrease Phigh (drop) by 2 cmH2O and increase Thigh (stretch) by 0.5–2 seconds. This progressively reduces mean airway pressure while maintaining oxygenation, eventually converting APRV to continuous CPAP."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"patient-ventilator-dyssynchrony",title:"Patient-Ventilator Dyssynchrony",category:"Mechanical Ventilation",seoTitle:"Patient-Ventilator Dyssynchrony – Types, Detection & Management | RRT",seoDescription:"Learn patient-ventilator dyssynchrony: trigger, flow, cycle asynchrony detection and management for the RRT exam.",seoKeywords:["patient ventilator dyssynchrony","trigger asynchrony","auto-triggering","double triggering","flow starvation","RRT exam"],overview:"Patient-ventilator dyssynchrony occurs when the ventilator's mechanical breath delivery does not match the patient's neural respiratory drive. It affects up to 25% of ventilator breaths and is associated with increased work of breathing, prolonged ventilation, increased sedation use, and potentially worse outcomes. Major types: trigger, flow, and cycle dyssynchrony.",mechanismPhysiology:"Trigger dyssynchrony: (1) Ineffective triggering — patient effort fails to trigger the ventilator (common with auto-PEEP, weak effort, or insensitive trigger). (2) Auto-triggering — ventilator delivers breaths without patient effort (cardiac oscillations, circuit leak, water in circuit). (3) Double triggering — two ventilator breaths delivered for one patient effort (Vt too small, Ti too short). Flow dyssynchrony: (4) Flow starvation — set flow rate insufficient for patient demand in VC mode (patient 'pulling' against ventilator). Cycle dyssynchrony: (5) Premature cycling — ventilator terminates inspiration before patient finishes inhaling. (6) Delayed cycling — ventilator continues inspiration after patient wants to exhale.",clinicalRelevance:"Dyssynchrony increases WOB, patient discomfort, and may increase VILI (double triggering delivers twice the set Vt). Asynchrony index > 10% is associated with longer ventilation duration and ICU stay. Detection requires systematic waveform analysis — most dyssynchrony is missed without graphics review. RT expertise in waveform interpretation is essential for optimizing patient-ventilator interaction.",signsSymptoms:"Flow starvation: concave scooping of the pressure-time waveform during inspiration in VC mode, patient accessory muscle use, tachypnea. Ineffective triggering: visible patient effort (abdominal movement) without ventilator triggering, deflections on pressure/flow waveform without triggered breaths. Auto-triggering: ventilator rate exceeds set rate without apparent patient effort. Double triggering: two rapidly sequential breaths with short expiratory time between.",assessment:"Systematic waveform analysis: (1) Pressure scalar — look for scooping (flow starvation), trigger delays, unexpected deflections. (2) Flow scalar — look for ineffective triggers (small flow deflections without triggered breath), incomplete exhalation (auto-PEEP). (3) Match ventilator rate to observed patient RR. (4) Calculate asynchrony index (AI) = number of asynchronous events / total breaths × 100%.",management:"Ineffective triggering: reduce auto-PEEP (if present), increase trigger sensitivity, apply external PEEP at 80% of auto-PEEP, reduce sedation. Auto-triggering: decrease trigger sensitivity, drain circuit water, check for leaks. Flow starvation: increase flow rate in VC, or switch to PC mode (variable flow). Double triggering: increase Vt (if safe), increase inspiratory time, ensure adequate sedation. Cycle asynchrony: adjust cycling criteria (% of peak flow for PSV), adjust Ti.",complications:"Increased work of breathing, patient distress, air trapping from double triggering, ventilator-induced diaphragm dysfunction, increased sedation requirements, prolonged weaning.",clinicalPearls:["Flow starvation shows as a CONCAVE (scooped out) pressure waveform during inspiration in VC mode","Switching from VC to PC mode often resolves flow dyssynchrony — PC provides variable flow to match demand","External PEEP at 80% of measured auto-PEEP reduces ineffective triggering","An asynchrony index > 10% is clinically significant and should prompt intervention"],examPitfalls:["Not recognizing flow starvation on the pressure-time waveform","Increasing sedation as first response to dyssynchrony instead of adjusting ventilator settings","Confusing auto-triggering (too sensitive) with ineffective triggering (not sensitive enough)","Not knowing that double triggering can deliver twice the intended tidal volume"],faqJson:[{question:"What is flow starvation and how is it identified?",answer:"Flow starvation occurs when the set inspiratory flow rate in volume control is insufficient for the patient's demand. The pressure-time waveform shows a concave (scooped) appearance during inspiration as the patient generates negative pressure trying to get more flow. Treatment: increase flow rate or switch to pressure control."},{question:"How is auto-PEEP related to ineffective triggering?",answer:"Auto-PEEP creates an inspiratory threshold load — the patient must first overcome the auto-PEEP level before generating enough negative pressure to reach the ventilator's trigger threshold. This makes triggering more difficult and many efforts fail. Applying external PEEP at 80% of auto-PEEP reduces this threshold."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"ventilator-modes-comparison",title:"Ventilator Modes Comparison",category:"Mechanical Ventilation",seoTitle:"Ventilator Modes – VC, PC, PSV, SIMV & Adaptive Modes | RRT",seoDescription:"Compare ventilator modes: volume control, pressure control, PSV, SIMV, PRVC, and adaptive support ventilation for the RRT exam.",seoKeywords:["ventilator modes","volume control","pressure control","PSV","SIMV","PRVC","adaptive support","RRT exam"],overview:"Mechanical ventilation modes define how the ventilator delivers breaths: what triggers the breath, what limits it, and what cycles it off. Understanding mode classification is essential for appropriate ventilator management. Primary modes: volume-controlled (VC), pressure-controlled (PC), pressure support ventilation (PSV), SIMV, and dual/adaptive modes (PRVC, ASV).",mechanismPhysiology:"Volume Control (VC/VCV): set Vt and flow rate are guaranteed; pressure varies with compliance and resistance. Pressure Control (PC/PCV): set pressure is applied; Vt varies with compliance, resistance, and patient effort. Pressure Support (PSV): patient-triggered, pressure-limited, flow-cycled (breath terminates when flow drops to 25% of peak — patient controls timing). SIMV: combines mandatory breaths with spontaneous breaths (PSV between mandatory breaths). PRVC: adaptive mode — targets a set Vt using pressure control (adjusts pressure breath-by-breath to achieve target Vt). Advantage: guaranteed Vt with decelerating flow pattern of PC.",clinicalRelevance:"No mode has been shown to improve mortality vs another in RCTs. Mode selection depends on clinical goals: VC for guaranteed Vt delivery (ARDS — ensures lung-protective 6 mL/kg), PC for flow dyssynchrony or when peak pressure is high (flow varies with demand), PSV for spontaneous breathing and weaning assessment, SIMV historically popular but associated with slower weaning than PSV or T-piece trials. PRVC/adaptive modes gaining popularity in ICU — combine Vt targeting with variable flow.",signsSymptoms:"VC indicators: predictable Vt delivery, constant flow pattern, variable PIP (monitor Pplat). PC indicators: variable Vt (monitor closely), decelerating flow, constant PIP, better patient comfort in some patients. PSV indicators: patient controls RR and Ti, appropriate for spontaneous breathing patients. Mode-related issues: flow starvation in VC, variable Vt in PC, apnea risk in pure PSV.",assessment:"VC: monitor PIP, Pplat (inspiratory hold), driving pressure, auto-PEEP. PC: monitor Vt (can vary with compliance changes — alarm if drops), inspiratory time, flow pattern. PSV: monitor Vt, RR, minute ventilation (no guaranteed backup in some ventilators). SIMV: monitor mandatory and spontaneous Vt separately. All modes: ABG, SpO2, patient comfort, dyssynchrony assessment.",management:"Acute respiratory failure: VC (guaranteed Vt for lung protection) or PC (if flow dyssynchrony). Weaning: PSV with decreasing support, or spontaneous breathing trials. PRVC: gaining popularity as it combines benefits of both VC and PC. Apnea backup: essential with PSV — set backup rate and apnea ventilation parameters. Mode selection should be individualized based on patient pathophysiology and clinical goals.",complications:"VC: flow starvation, high PIP in non-compliant lungs. PC: variable Vt (may be too high or too low). PSV: apnea if patient effort ceases. SIMV: slower weaning, increased WOB between mandatory breaths. PRVC: may undershoot or overshoot Vt during transitions.",clinicalPearls:["There is NO single 'best' ventilator mode — selection should be based on clinical goals and patient physiology","VC guarantees Vt but not pressure; PC guarantees pressure but not Vt — know the tradeoffs","PSV is patient-triggered and flow-cycled — the patient controls rate, inspiratory time, and tidal volume","SIMV with low mandatory rates increases work of breathing — avoid low-rate SIMV during weaning"],examPitfalls:["Not understanding the difference between VC (guaranteed volume) and PC (guaranteed pressure)","Using PSV without apnea backup ventilation","Thinking SIMV is the best weaning mode — evidence favors PSV or T-piece/SBT approach","Not monitoring Vt in pressure control mode — it can change significantly with compliance changes"],faqJson:[{question:"What is the key difference between VC and PC?",answer:"In VC, the ventilator guarantees a set tidal volume and flow — pressure is the dependent variable. In PC, the ventilator guarantees a set pressure — tidal volume is the dependent variable. VC ensures consistent ventilation; PC provides variable flow that may improve patient comfort."},{question:"What is PRVC and why is it used?",answer:"Pressure-Regulated Volume Control is a dual mode that targets a set tidal volume using pressure control delivery. It adjusts the inspiratory pressure breath-by-breath to achieve the target Vt, combining the guaranteed Vt of VC with the decelerating flow pattern and variable flow of PC."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"auto-peep-management",title:"Auto-PEEP (Intrinsic PEEP)",category:"Mechanical Ventilation",seoTitle:"Auto-PEEP – Intrinsic PEEP Detection & Management | RRT",seoDescription:"Learn auto-PEEP: causes, detection with expiratory hold, hemodynamic effects, and management strategies for the RRT exam.",seoKeywords:["auto-PEEP","intrinsic PEEP","air trapping","dynamic hyperinflation","expiratory hold","RRT exam"],overview:"Auto-PEEP (intrinsic PEEP) is the positive alveolar pressure remaining at end-expiration due to incomplete exhalation. It occurs when expiratory time is insufficient to allow full lung deflation, common in obstructive diseases (COPD, asthma) and with high ventilator rates or prolonged inspiratory times. Auto-PEEP has significant hemodynamic and respiratory consequences.",mechanismPhysiology:"Auto-PEEP occurs when the expiratory time constant (compliance × resistance) is long relative to available expiratory time. Causes: high airway resistance (COPD, asthma, secretions), high compliance (emphysema), short expiratory time (high RR, high I:E ratio, prolonged inspiration). Consequences: (1) increased intrathoracic pressure → decreased venous return → decreased CO → hypotension. (2) Increased work of breathing (patient must overcome auto-PEEP threshold before triggering). (3) Overdistension → increased risk of barotrauma. (4) Inaccurate hemodynamic measurements (falsely elevated CVP/PCWP).",clinicalRelevance:"Auto-PEEP is a HIDDEN danger — it is not displayed on the ventilator's standard pressure readings because the ventilator PEEP gauge only shows set (extrinsic) PEEP. Detection requires: (1) Flow-time waveform — expiratory flow does not return to zero. (2) Expiratory hold maneuver — measures total PEEP (displayed on manometer); auto-PEEP = total PEEP − set PEEP. Clinically significant auto-PEEP: > 5 cmH2O. Common in ventilated COPD/asthma patients.",signsSymptoms:"Clinical signs: unexplained hypotension (especially after intubation in COPD/asthma), difficulty triggering the ventilator (ineffective efforts), progressive hyperinflation on CXR, elevated PIP with normal Pplat (sometimes), decreasing Vt in PC mode, hemodynamic instability with positive pressure ventilation.",assessment:"Detection: (1) Observe flow-time waveform — if expiratory flow is cut off before reaching zero, auto-PEEP is present. (2) Perform expiratory hold maneuver (requires no patient effort — patient must not be breathing): total PEEP is displayed. Auto-PEEP = total PEEP − set PEEP. (3) Measure in paralyzed or deeply sedated patients for accuracy (spontaneous efforts invalidate the measurement).",management:"Reduce auto-PEEP: (1) Decrease RR (longer expiratory time). (2) Decrease Vt (faster delivery). (3) Increase inspiratory flow rate in VC (shorter Ti → longer Te). (4) Decrease I:E ratio. (5) Bronchodilator therapy (reduce resistance). (6) Suction secretions. (7) Larger ET tube if possible. Apply external PEEP: 80% of measured auto-PEEP to facilitate triggering (does not significantly increase total PEEP if set below auto-PEEP level). Emergency: if hemodynamic collapse suspected from severe auto-PEEP → disconnect from ventilator briefly to decompress.",complications:"Hemodynamic collapse, barotrauma (pneumothorax), ineffective triggering, patient-ventilator dyssynchrony, increased work of breathing, inaccurate hemodynamic monitoring.",clinicalPearls:["Auto-PEEP is invisible on standard ventilator display — you must actively look for it","Disconnecting the patient from the ventilator briefly can be LIFE-SAVING in severe auto-PEEP with hemodynamic collapse","External PEEP at 80% of auto-PEEP facilitates triggering WITHOUT significantly increasing total PEEP","The flow-time waveform is your best real-time indicator — if expiratory flow doesn't reach zero, auto-PEEP exists"],examPitfalls:["Not checking for auto-PEEP when a COPD/asthma patient is hypotensive on the ventilator","Thinking the ventilator PEEP display shows total PEEP — it only shows SET PEEP","Not performing an expiratory hold maneuver to quantify auto-PEEP","Increasing set PEEP above auto-PEEP level — this adds to total PEEP and worsens hyperinflation"],faqJson:[{question:"How is auto-PEEP measured?",answer:"Perform an expiratory hold maneuver on the ventilator (patient should be passive — not actively breathing). The ventilator displays total PEEP. Auto-PEEP = total PEEP − set (extrinsic) PEEP. The flow-time waveform also shows auto-PEEP when expiratory flow does not return to zero baseline."},{question:"Why does disconnecting the ventilator help in severe auto-PEEP?",answer:"Disconnection allows full exhalation, releasing trapped gas and reducing intrathoracic pressure. This immediately improves venous return and cardiac output. It is an emergency maneuver used when auto-PEEP causes hemodynamic collapse."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"ventilator-alarms-troubleshooting",title:"Ventilator Alarms & Troubleshooting",category:"Mechanical Ventilation",seoTitle:"Ventilator Alarms – Troubleshooting High Pressure, Low Volume | RRT",seoDescription:"Learn ventilator alarm troubleshooting: high pressure, low pressure, low volume, apnea alarms, and systematic approach for the RRT exam.",seoKeywords:["ventilator alarms","high pressure alarm","low pressure alarm","troubleshooting","ventilator management","RRT exam"],overview:"Ventilator alarm management is a critical RT competency. Alarms indicate changes in patient condition, circuit integrity, or ventilator function that require immediate assessment. The systematic approach: always assess the PATIENT first (not the ventilator), then evaluate the circuit, and finally the ventilator. High priority alarms (high pressure, low volume, apnea) require immediate response.",mechanismPhysiology:"Alarms are based on set parameters that define acceptable ranges for pressure, volume, flow, and rate. High pressure alarm: triggered when circuit pressure exceeds the set limit. Causes relate to increased resistance (secretions, bronchospasm, kinked tube, biting) or decreased compliance (tension pneumothorax, pulmonary edema, abdominal distension, patient-ventilator dyssynchrony). Low pressure/volume alarm: triggered by air leak or disconnection. Apnea alarm: no breath detected within the set apnea interval.",clinicalRelevance:"Approach: DOPE mnemonic for acute deterioration — Displacement (tube), Obstruction (tube/secretions), Pneumothorax, Equipment failure. Always ventilate the patient manually with a BVM while troubleshooting if the patient is in distress. Never silence alarms without identifying and addressing the cause. High-pressure alarm with sudden onset: think tension pneumothorax, mucus plug, right mainstem migration, or patient biting tube.",signsSymptoms:"High pressure alarm: PIP exceeds alarm limit. Causes: bronchospasm, secretions, mucus plug, ET tube biting/kinking, tension pneumothorax, decreased compliance, patient coughing/fighting ventilator, circuit water accumulation. Low pressure/low volume alarm: circuit disconnection, cuff leak, circuit leak, chest tube air leak. Apnea alarm: CNS depression, oversedation, neuromuscular blockade wearing off, patient fatigue.",assessment:"Patient first: assess respiratory distress, SpO2, chest movement, breath sounds. Circuit: check connections, inspect for kinks/water, verify ET tube position. Pass suction catheter (rules out obstruction). Ventilator: check settings, alarm parameters, self-test. If unable to resolve and patient is in distress: disconnect from ventilator and manually ventilate with BVM + 100% O2 while calling for help.",management:"High pressure: suction (secretions), bronchodilator (bronchospasm), reposition tube (kink/migration), bite block (biting), needle decompression (tension pneumothorax). Low pressure/volume: reconnect circuit, replace tube if cuff leak irreparable, tighten connections. Apnea: stimulate patient, check sedation level, verify trigger sensitivity, ensure backup ventilation is set. Document alarm, cause, and intervention.",complications:"Delayed response to alarms causing patient harm, alarm fatigue (desensitization from excessive non-critical alarms), missed critical alarms due to improper alarm settings.",clinicalPearls:["ALWAYS assess the PATIENT first when an alarm sounds — not the ventilator","Use the DOPE mnemonic: Displacement, Obstruction, Pneumothorax, Equipment failure","If you cannot quickly identify the cause and the patient is deteriorating — disconnect and bag-ventilate with 100% O2","High pressure alarm + absent breath sounds unilaterally = tension pneumothorax until proven otherwise"],examPitfalls:["Going to the ventilator first instead of assessing the patient","Silencing alarms without identifying the cause","Not passing a suction catheter when high-pressure alarm sounds (to rule out obstruction)","Not having a manual resuscitation bag at every ventilator bedside"],faqJson:[{question:"What is the DOPE mnemonic?",answer:"A systematic approach to acute deterioration in ventilated patients: D (Displacement of the ET tube), O (Obstruction of the tube by secretions/kinking), P (Pneumothorax), E (Equipment failure). Check each in order while maintaining oxygenation."},{question:"When should you disconnect the patient from the ventilator?",answer:"When the cause of distress cannot be quickly identified and the patient is deteriorating. Disconnecting and manually ventilating with a BVM and 100% O2 eliminates the ventilator as a variable, addresses possible auto-PEEP, and ensures oxygenation while troubleshooting."}],relatedLessonIds:[],relatedQuestionIds:[]},

  // ═══ ABG Interpretation (3 more) ═══
  {slug:"abg-case-study-approach",title:"ABG Case Study Approach",category:"ABG Interpretation",seoTitle:"ABG Case Study Approach – Systematic Interpretation Method | RRT",seoDescription:"Master a systematic ABG interpretation approach: assess oxygenation, acid-base status, compensation, and clinical correlation for the RRT exam.",seoKeywords:["ABG interpretation","systematic approach","acid-base analysis","oxygenation assessment","clinical correlation","RRT exam"],overview:"A systematic approach to ABG interpretation ensures accurate assessment in every clinical scenario. The recommended sequence: (1) Assess oxygenation (PaO2, SaO2, P/F ratio), (2) Evaluate pH (acidemic, alkalemic, or normal), (3) Identify primary disorder (respiratory vs metabolic), (4) Assess compensation (expected vs actual), (5) Calculate anion gap if metabolic acidosis, (6) Correlate with clinical picture.",mechanismPhysiology:"Step 1 — Oxygenation: PaO2 normal 80–100 mmHg on room air (decreases 1 mmHg per year after age 60). Calculate expected PaO2 = 104 − (0.27 × age). P/F ratio = PaO2/FiO2 (< 300 = acute lung injury, < 200 = ARDS). Step 2 — pH: < 7.35 = acidemia, > 7.45 = alkalemia. Step 3 — Primary disorder: if pH < 7.35, the primary process is whichever value (PaCO2 or HCO3) moves in the direction that causes acidosis. Step 4 — Compensation: expected compensation formulas (Winter's formula for metabolic acidosis: expected PaCO2 = 1.5 × HCO3 + 8 ± 2). Step 5 — Anion gap = Na − (Cl + HCO3), normal 8–12 mEq/L. Step 6 — Delta-delta ratio for mixed disorders.",clinicalRelevance:"Common exam scenarios: COPD exacerbation (respiratory acidosis with metabolic compensation), diabetic ketoacidosis (metabolic acidosis with respiratory compensation, elevated AG), anxiety hyperventilation (respiratory alkalosis), vomiting (metabolic alkalosis), ARDS (respiratory alkalosis early, respiratory acidosis late). Mixed disorders: if compensation is more or less than expected, a second primary disorder is present.",signsSymptoms:"Acidemia signs: tachypnea (respiratory compensation), confusion, cardiac arrhythmias, hypotension. Alkalemia signs: tetany, paresthesias, arrhythmias, seizures. Hypoxemia: tachypnea, tachycardia, cyanosis, altered mentation.",assessment:"Systematic checklist: (1) PaO2 — hypoxemic? (2) pH — acidemic or alkalemic? (3) PaCO2 — respiratory component (> 45 = acid, < 35 = alkaline). (4) HCO3 — metabolic component (< 22 = acid, > 26 = alkaline). (5) Does compensation match expected? (6) Anion gap if metabolic acidosis. (7) Delta-delta if AG elevated. (8) Clinical correlation — does the ABG make sense for this patient?",management:"Treatment targets the underlying cause, not just the numbers. Respiratory acidosis: improve ventilation (NIV, intubation, bronchodilators). Respiratory alkalosis: treat underlying cause (anxiety, pain, sepsis, PE). Metabolic acidosis: treat underlying cause (fluids for DKA, dialysis for renal failure, NaHCO3 if pH < 7.10). Metabolic alkalosis: volume repletion, correct hypokalemia/hypochloremia.",complications:"Overcorrection (rapid correction of chronic hypercapnia can cause post-hypercapnic metabolic alkalosis), failure to identify mixed disorders, treatment based on numbers alone without clinical correlation.",clinicalPearls:["Always start with pH — this tells you the PRIMARY direction of the disturbance","If compensation is MORE than expected, a second primary process is present","Winter's formula (expected PaCO2 = 1.5 × HCO3 + 8 ± 2) is essential for detecting mixed disorders","A normal pH does NOT mean normal — it may represent two opposing primary disorders"],examPitfalls:["Forgetting to assess oxygenation — many students jump straight to acid-base","Not applying compensation formulas — unable to detect mixed disorders","Treating numbers without clinical context (a chronic COPD patient with PaCO2 55 may be at their baseline)","Not calculating anion gap when metabolic acidosis is present"],faqJson:[{question:"What is Winter's formula and when is it used?",answer:"Winter's formula predicts the expected PaCO2 in primary metabolic acidosis: expected PaCO2 = (1.5 × HCO3) + 8 ± 2. If actual PaCO2 differs from expected, a concurrent respiratory disorder is present (higher = concurrent respiratory acidosis, lower = concurrent respiratory alkalosis)."},{question:"What does the delta-delta ratio indicate?",answer:"Delta-delta compares the change in anion gap to the change in bicarbonate. Ratio > 2: concurrent metabolic alkalosis. Ratio < 1: concurrent non-anion gap metabolic acidosis. Ratio 1–2: pure anion gap metabolic acidosis."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"abg-expected-compensation",title:"ABG Expected Compensation Rules",category:"ABG Interpretation",seoTitle:"ABG Compensation – Expected Responses & Mixed Disorders | RRT",seoDescription:"Master ABG compensation rules: Winter's formula, expected CO2/HCO3 changes for acute and chronic respiratory disorders for the RRT exam.",seoKeywords:["ABG compensation","Winter's formula","acute chronic respiratory acidosis","metabolic compensation","mixed acid-base","RRT exam"],overview:"Understanding expected compensation is essential for detecting mixed acid-base disorders. Each primary disorder triggers a predictable compensatory response. If actual compensation differs from expected, a second primary disorder coexists. Key formulas: Winter's formula (metabolic acidosis), and acute/chronic compensation rules for respiratory disorders.",mechanismPhysiology:"Respiratory compensation (for metabolic disorders): occurs within minutes to hours. Metabolic compensation (for respiratory disorders): takes 3–5 days to reach full effect. Acute respiratory acidosis: HCO3 rises 1 mEq/L per 10 mmHg rise in PaCO2. Chronic respiratory acidosis: HCO3 rises 3.5 mEq/L per 10 mmHg rise. Acute respiratory alkalosis: HCO3 falls 2 mEq/L per 10 mmHg drop in PaCO2. Chronic respiratory alkalosis: HCO3 falls 5 mEq/L per 10 mmHg drop. Metabolic acidosis (Winter's): expected PaCO2 = 1.5 × HCO3 + 8 ± 2. Metabolic alkalosis: expected PaCO2 = 0.7 × HCO3 + 21 ± 2.",clinicalRelevance:"Example: Patient with DKA — pH 7.20, PaCO2 24, HCO3 10. Winter's formula: expected PaCO2 = 1.5(10) + 8 = 23 ± 2 (range 21–25). Actual PaCO2 = 24, within range = appropriate compensation, pure metabolic acidosis. If PaCO2 were 35 (higher than expected) = concurrent respiratory acidosis. If PaCO2 were 15 (lower than expected) = concurrent respiratory alkalosis. This approach detects hidden secondary disorders that change management.",signsSymptoms:"Clue to mixed disorders: pH more abnormal than expected for a single process, compensation that doesn't match formulas, clinical scenario suggesting multiple etiologies (e.g., COPD patient with vomiting = respiratory acidosis + metabolic alkalosis).",assessment:"Step-by-step: (1) Identify primary disorder from pH. (2) Calculate expected compensation using appropriate formula. (3) Compare actual to expected. (4) If actual = expected: single disorder with appropriate compensation. (5) If actual ≠ expected: mixed disorder present. (6) Calculate anion gap for all metabolic acidoses. (7) Calculate delta-delta if AG is elevated.",management:"Mixed disorders require treatment of BOTH components. Example: COPD exacerbation (respiratory acidosis) + severe diarrhea (metabolic acidosis) → treat both bronchospasm and dehydration/electrolytes. Compensation is NEVER complete (pH never fully normalizes from compensation alone) except in chronic respiratory alkalosis.",complications:"Failure to detect mixed disorders leads to incomplete treatment. Overcompensation does NOT occur — if pH appears overcompensated, a second primary disorder is present.",clinicalPearls:["Compensation NEVER overcorrects — pH never crosses to the opposite side of 7.40 from compensation alone","Metabolic compensation for respiratory disorders takes 3–5 days — acute vs chronic changes clinical approach","An HCO3 change that exceeds the expected compensation for respiratory acidosis indicates concurrent metabolic alkalosis","Compensation should be checked in EVERY ABG — it reveals hidden secondary disorders"],examPitfalls:["Not memorizing compensation formulas — they are essential for RRT/TMC exams","Thinking 'partially compensated' without calculating whether compensation matches expected","Not distinguishing acute from chronic respiratory acid-base changes","Assuming a normal pH means no acid-base disturbance (could be two opposing disorders)"],faqJson:[{question:"How do you distinguish acute from chronic respiratory acidosis?",answer:"Acute respiratory acidosis: HCO3 rises only 1 mEq/L per 10 mmHg rise in PaCO2 (minimal renal compensation). Chronic: HCO3 rises 3.5 mEq/L per 10 mmHg (full renal compensation over 3–5 days). If HCO3 is between acute and chronic expected values, the disorder may be in transition."},{question:"Can compensation ever normalize the pH?",answer:"Generally no — compensation reduces the pH deviation but does not return it to 7.40. The one exception is chronic respiratory alkalosis, where metabolic compensation may return pH to normal or near-normal. If pH is 7.40 in any other scenario, suspect two opposing primary disorders."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"abg-anion-gap",title:"Anion Gap & Metabolic Acidosis Classification",category:"ABG Interpretation",seoTitle:"Anion Gap – AGMA vs NAGMA Classification | RRT Encyclopedia",seoDescription:"Learn anion gap calculation: MUDPILES mnemonic, NAGMA causes, delta-delta ratio, and clinical interpretation for the RRT exam.",seoKeywords:["anion gap","metabolic acidosis","MUDPILES","NAGMA","AGMA","delta-delta","lactic acidosis","RRT exam"],overview:"The anion gap (AG) is essential for classifying metabolic acidosis as either anion gap metabolic acidosis (AGMA) or non-anion gap/hyperchloremic metabolic acidosis (NAGMA). AG = Na − (Cl + HCO3). Normal AG: 8–12 mEq/L (some labs 10–14 with different assays). An elevated AG indicates the presence of unmeasured anions (lactate, ketoacids, uremic toxins, toxic alcohols).",mechanismPhysiology:"Electroneutrality principle: total cations = total anions. Measured cations (primarily Na+) > measured anions (Cl− + HCO3−) = the 'gap' represents unmeasured anions (albumin, phosphate, sulfate, organic acids). In AGMA: an acid (HA) dissociates to H+ + A−. H+ is buffered by HCO3 (HCO3 falls). A− (unmeasured anion) accumulates, increasing the AG. In NAGMA: HCO3 is lost (diarrhea, RTA) and replaced by Cl− → AG remains normal but HCO3 is low.",clinicalRelevance:"AGMA causes (MUDPILES): Methanol, Uremia, Diabetic ketoacidosis, Propylene glycol, Isoniazid/Iron, Lactic acidosis (most common), Ethylene glycol, Salicylates. Lactic acidosis is the most common cause of AGMA in clinical practice. NAGMA causes (HARDUPS): Hyperalimentation, Acetazolamide, RTA, Diarrhea (most common), Ureteral diversion, Pancreatic fistula, Saline infusion. Delta-delta ratio: change in AG / change in HCO3. Ratio > 2 = concurrent metabolic alkalosis. Ratio < 1 = concurrent NAGMA.",signsSymptoms:"Metabolic acidosis signs: Kussmaul breathing (deep, rapid — respiratory compensation), altered mental status, hypotension, cardiac arrhythmias. DKA: fruity breath odor, polyuria, polydipsia. Lactic acidosis: signs of tissue hypoperfusion (shock, sepsis). Toxic ingestion: visual changes (methanol), flank pain (ethylene glycol).",assessment:"Calculate AG from basic metabolic panel: AG = Na − (Cl + HCO3). If AG > 12: AGMA — investigate with lactate, ketones, BUN/Cr, osmolar gap, toxicology. If AG normal (8–12) with low HCO3: NAGMA — check urine AG, urine pH for RTA classification. Correct AG for albumin: corrected AG = calculated AG + 2.5 × (4 − measured albumin). Hypoalbuminemia falsely normalizes the AG.",management:"Treat the underlying cause: DKA (insulin, fluids, electrolytes), lactic acidosis (restore perfusion, treat sepsis), toxic ingestion (specific antidotes: fomepizole for methanol/ethylene glycol). Sodium bicarbonate: controversial — consider if pH < 7.10 or HCO3 < 8. NAGMA from diarrhea: IV fluids with bicarbonate or lactated Ringer's. RTA: oral bicarbonate supplementation.",complications:"Severe acidemia (pH < 7.10): cardiac dysfunction, vasodilation, decreased response to catecholamines. Rapid correction with bicarbonate: hypokalemia, overshoot alkalosis, paradoxical CSF acidosis.",clinicalPearls:["ALWAYS correct the AG for albumin — hypoalbuminemia hides the true AG elevation","Lactic acidosis is the most common cause of AGMA in clinical practice — check lactate first","Delta-delta ratio detects HIDDEN concurrent disorders in AGMA patients","Saline infusion (0.9% NaCl) causes hyperchloremic NAGMA — be aware during aggressive resuscitation"],examPitfalls:["Not calculating the anion gap when metabolic acidosis is identified","Forgetting to correct AG for albumin (add 2.5 for each 1 g/dL albumin below 4)","Not calculating delta-delta ratio when AG is elevated","Confusing AGMA causes (MUDPILES) with NAGMA causes (HARDUPS)"],faqJson:[{question:"Why must the anion gap be corrected for albumin?",answer:"Albumin is the major unmeasured anion contributing to the normal anion gap. In hypoalbuminemia (common in critically ill patients), the baseline AG is lower, potentially masking an elevated AG from organic acids. Add 2.5 mEq/L to the AG for each 1 g/dL albumin below 4 g/dL."},{question:"What does the delta-delta ratio reveal?",answer:"If AG is elevated, the delta-delta ratio (ΔAG/ΔHCO3) reveals hidden concurrent metabolic disorders: ratio > 2 suggests concurrent metabolic alkalosis (HCO3 hasn't fallen as much as expected), ratio < 1 suggests concurrent non-AG metabolic acidosis (HCO3 has fallen more than expected from the AG acidosis alone)."}],relatedLessonIds:[],relatedQuestionIds:[]},

  // ═══ Oxygen Therapy (2 more) ═══
  {slug:"oxygen-delivery-devices-comparison",title:"Oxygen Delivery Devices Comparison",category:"Oxygen Therapy",seoTitle:"Oxygen Delivery Devices – Nasal Cannula to Non-Rebreather | RRT",seoDescription:"Compare oxygen delivery devices: nasal cannula, simple mask, Venturi mask, partial and non-rebreather masks, and FiO2 delivery for the RRT exam.",seoKeywords:["oxygen delivery","nasal cannula","Venturi mask","non-rebreather","simple mask","FiO2","oxygen therapy","RRT exam"],overview:"Understanding oxygen delivery devices, their FiO2 capabilities, and appropriate clinical applications is fundamental for respiratory therapists. Devices are classified as low-flow (variable FiO2) or high-flow (fixed FiO2). Selection depends on the required FiO2, need for precise delivery, patient comfort, and clinical condition.",mechanismPhysiology:"Low-flow devices provide supplemental O2 at flows below the patient's inspiratory demand — room air is entrained to make up the difference, creating variable FiO2 that changes with the patient's respiratory pattern. High-flow devices provide total flow that meets or exceeds the patient's peak inspiratory flow rate, delivering a fixed, predictable FiO2 regardless of breathing pattern. Air-entrainment (Venturi) devices use the Bernoulli principle: oxygen flowing through a jet nozzle creates negative lateral pressure that entrains room air through side ports in a precise ratio.",clinicalRelevance:"Nasal cannula: 1–6 L/min, ~24–44% FiO2 (add ~4% per L/min). Simple mask: 5–10 L/min, 35–50% FiO2 (minimum 5 L/min to prevent CO2 rebreathing). Partial rebreather: 6–10 L/min, 40–70% FiO2 (reservoir bag partially refills with exhaled gas). Non-rebreather (NRB): 10–15 L/min, 60–80% FiO2 (one-way valves prevent room air entrainment). Venturi mask: precise FiO2 from 24–50% (color-coded entrainment ports). HFNC: up to 60 L/min, 21–100% FiO2.",signsSymptoms:"Indications for escalation: increasing FiO2 requirement, persistent desaturation on current device, respiratory distress despite O2, transition from low to high FiO2 needs. Signs of appropriate device: stable SpO2 at target, comfortable breathing, adequate flow for patient's demand.",assessment:"Match device to clinical need: mild hypoxemia → nasal cannula. Moderate hypoxemia → simple mask or Venturi. COPD requiring precise FiO2 → Venturi mask (24–28%). Severe hypoxemia → NRB mask. Very severe / need for positive pressure → HFNC or NIV. Assess reservoir bag inflation (should never fully deflate during inspiration on NRB).",management:"Start with the lowest device and FiO2 to achieve target SpO2 (92–96% for most patients, 88–92% for COPD). Escalate systematically: NC → simple mask → Venturi → NRB → HFNC → NIV → intubation. Always ensure minimum flow rates: simple mask ≥ 5 L/min, NRB ≥ 10 L/min (keep reservoir inflated). Humidification: recommended for flows > 4 L/min via NC.",complications:"Oxygen toxicity (high FiO2 > 0.6 for prolonged periods — absorption atelectasis, oxidative injury), nasal drying/epistaxis (NC without humidification), CO2 rebreathing (simple mask < 5 L/min), skin irritation (mask contact), aspiration risk with vomiting while wearing a mask.",clinicalPearls:["Nasal cannula at 1 L/min provides ~24% FiO2 — add approximately 4% per additional liter (rough estimate)","The non-rebreather can deliver up to 80% FiO2 — NOT 100% (there is always some room air entrainment around the mask)","Venturi masks are the GOLD STANDARD for precise FiO2 delivery — essential for COPD management","Simple mask requires MINIMUM 5 L/min flow to prevent CO2 rebreathing from the mask dead space"],examPitfalls:["Thinking a non-rebreather delivers 100% FiO2 — it delivers 60–80%","Running a simple mask below 5 L/min — causes CO2 rebreathing","Not using a Venturi mask when precise FiO2 is needed (COPD patients)","Forgetting that nasal cannula FiO2 varies with the patient's respiratory pattern"],faqJson:[{question:"Why is the Venturi mask preferred for COPD patients?",answer:"COPD patients require precise, controlled FiO2 (targeting SpO2 88–92%) to avoid oxygen-induced hypercapnia. The Venturi mask delivers a fixed FiO2 regardless of respiratory pattern because its total flow exceeds the patient's peak inspiratory demand. This precision is not achievable with low-flow devices."},{question:"What is the maximum FiO2 a non-rebreather can deliver?",answer:"60–80% FiO2 at 10–15 L/min. Despite having one-way valves, there is always some room air entrainment around the edges of the mask. For higher FiO2, HFNC or a closed system (NIV, intubation) is needed."}],relatedLessonIds:[],relatedQuestionIds:[]},

  // ═══ Additional entries to reach 200+ ═══
  {slug:"copd-gold-classification",title:"COPD GOLD Classification & Staging",category:"COPD Management",seoTitle:"COPD GOLD Classification – Spirometric Grading & Group Assignment | RRT",seoDescription:"Master COPD GOLD classification: spirometric grades 1–4, symptom assessment (CAT, mMRC), exacerbation history, and treatment groups for the RRT exam.",seoKeywords:["COPD GOLD","spirometry grading","FEV1","CAT score","mMRC","exacerbation","RRT exam"],overview:"The Global Initiative for Chronic Obstructive Lung Disease (GOLD) provides a standardized framework for COPD diagnosis, classification, and management. GOLD 2023 uses spirometric grades (1–4 based on post-bronchodilator FEV1) combined with symptom burden and exacerbation history to guide therapy. The ABE grouping system replaced the former ABCD system.",mechanismPhysiology:"Spirometric grades: GOLD 1 (mild): FEV1 ≥ 80% predicted. GOLD 2 (moderate): 50–79%. GOLD 3 (severe): 30–49%. GOLD 4 (very severe): < 30%. All require FEV1/FVC < 0.70 post-bronchodilator for diagnosis. Symptom assessment: mMRC dyspnea scale (0–4) or CAT score (0–40). Exacerbation history: moderate (requiring antibiotics/steroids) and severe (requiring hospitalization). GOLD 2023 ABE groups: A (low symptoms, low exacerbation risk), B (high symptoms, low exacerbation risk), E (any exacerbation history ≥ 2 moderate or ≥ 1 hospitalization).",clinicalRelevance:"Group A: PRN bronchodilator. Group B: LABA or LAMA. Group E: LAMA + LABA (if eosinophils ≥ 300: LABA + LAMA + ICS). Post-bronchodilator FEV1/FVC < 0.70 is required for COPD diagnosis — a single low FEV1 is not sufficient. BODE index (BMI, Obstruction, Dyspnea, Exercise) provides additional prognostic information beyond GOLD staging.",signsSymptoms:"Chronic cough, sputum production, progressive dyspnea on exertion, history of smoking or occupational exposure. Physical exam: barrel chest, pursed-lip breathing, prolonged expiration, diminished breath sounds, wheezing.",assessment:"Post-bronchodilator spirometry (essential for diagnosis): FEV1/FVC < 0.70. Symptom assessment: CAT ≥ 10 or mMRC ≥ 2 = high symptoms. Exacerbation history: ≥ 2 moderate or ≥ 1 hospitalization in past year = Group E. CXR/CT: hyperinflation, flattened diaphragms, bullae. Alpha-1 antitrypsin level in younger patients or those with family history.",management:"All groups: smoking cessation, vaccination (influenza, pneumococcal, COVID-19, Tdap, zoster), pulmonary rehabilitation. Group A: short-acting bronchodilator PRN. Group B: LABA or LAMA (LAMA preferred if monotherapy). Group E: LAMA + LABA; add ICS if eosinophils ≥ 300 cells/μL. Non-pharmacological: oxygen therapy if PaO2 ≤ 55, pulmonary rehabilitation, surgical options for select patients.",complications:"Acute exacerbations, respiratory failure, cor pulmonale, pneumothorax, depression/anxiety, cachexia, osteoporosis.",clinicalPearls:["GOLD 2023 replaced ABCD with ABE — Group C was removed, and all exacerbators are now Group E","Post-bronchodilator spirometry is REQUIRED for COPD diagnosis — pre-bronchodilator values are not sufficient","Eosinophil count guides ICS use in COPD: ≥ 300 favors ICS, < 100 favors against ICS","LAMA is generally preferred over LABA as initial monotherapy in COPD"],examPitfalls:["Using pre-bronchodilator spirometry for COPD diagnosis","Not knowing the updated ABE grouping system (replacing ABCD)","Prescribing ICS to all COPD patients — it is only for those with eosinophilia and/or frequent exacerbations","Confusing GOLD spirometric grades (1–4) with ABE treatment groups"],faqJson:[{question:"What changed from ABCD to ABE in GOLD 2023?",answer:"Groups C and D were merged into Group E (exacerbator). The previous system separated high-exacerbation patients by symptom burden (C vs D), but treatment recommendations were similar. Group E simplifies by grouping all patients with significant exacerbation history together."},{question:"When should ICS be added to COPD therapy?",answer:"ICS (combined with LABA ± LAMA) should be considered when blood eosinophils are ≥ 300 cells/μL and the patient has frequent exacerbations (Group E). ICS should be avoided when eosinophils are < 100 or the patient has recurrent pneumonia."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"asthma-copd-overlap",title:"Asthma-COPD Overlap (ACO)",category:"Asthma",seoTitle:"Asthma-COPD Overlap – Diagnosis & Management | RRT Encyclopedia",seoDescription:"Learn ACO: features of both asthma and COPD, diagnostic criteria, treatment approach, and clinical differentiation for the RRT exam.",seoKeywords:["asthma COPD overlap","ACO","ACOS","mixed disease","eosinophilic COPD","RRT exam"],overview:"Asthma-COPD overlap (ACO) describes patients who have features of both asthma and COPD simultaneously. These patients typically have persistent airflow limitation with significant bronchodilator reversibility, eosinophilic inflammation, and a history of asthma or atopy alongside smoking-related fixed obstruction. ACO affects 15–25% of patients with obstructive airways disease.",mechanismPhysiology:"ACO patients have components of both diseases: fixed airflow obstruction (COPD component — structural changes from smoking/chronic inflammation) combined with variable obstruction and eosinophilic/Type 2 inflammation (asthma component). This results in greater symptom variability than pure COPD, more frequent exacerbations, faster FEV1 decline, and poorer quality of life compared to either disease alone. The eosinophilic inflammation component responds to ICS, distinguishing management from pure COPD.",clinicalRelevance:"ACO patients have WORSE outcomes than pure asthma or COPD: more exacerbations, more hospitalizations, worse quality of life, and faster lung function decline. Key distinction: ACO patients NEED ICS (unlike many pure COPD patients) because of their eosinophilic/Type 2 inflammation component. ICS is a cornerstone of therapy, combined with LABA ± LAMA. Pure COPD treatment without ICS may be inadequate and harmful in ACO.",signsSymptoms:"Features suggesting ACO: persistent airflow limitation (FEV1/FVC < 0.70) PLUS significant bronchodilator reversibility (> 12% and 200 mL), history of asthma before age 40, atopy/allergies, symptom variability, blood eosinophils ≥ 300, elevated FeNO, smoking history with ≥ 10 pack-years.",assessment:"Spirometry: persistent obstruction (FEV1/FVC < 0.70) with significant reversibility. Blood eosinophils and FeNO (both typically elevated in ACO). Allergy testing if atopy suspected. DLCO (typically normal or near-normal in ACO, reduced in pure emphysema). CT chest to assess for emphysema, bronchial wall thickening.",management:"ICS + LABA is the cornerstone (ICS is essential — do NOT omit). Add LAMA for additional bronchodilation if needed. Smoking cessation. Avoid LABA monotherapy (asthma component makes this dangerous). Consider biologic therapy for severe uncontrolled ACO with eosinophilia. Pulmonary rehabilitation. Vaccination.",complications:"Frequent exacerbations, accelerated lung function decline, increased healthcare utilization, reduced quality of life compared to either disease alone.",clinicalPearls:["ACO patients MUST receive ICS — omitting it (as might be done in pure COPD) leaves the eosinophilic component untreated","Significant bronchodilator reversibility (> 12% and 200 mL) in a smoker with fixed obstruction suggests ACO","Blood eosinophils ≥ 300 in a COPD patient should raise suspicion for ACO","ACO has worse outcomes than either pure asthma or pure COPD — recognize and treat both components"],examPitfalls:["Treating ACO as pure COPD without ICS — misses the asthma component","Not checking for bronchodilator reversibility in COPD patients","Ignoring eosinophil count in patients with fixed obstruction","Using LABA monotherapy in ACO (dangerous due to asthma component)"],faqJson:[{question:"How is ACO different from pure COPD?",answer:"ACO has features of both diseases: fixed obstruction (COPD) plus variable obstruction, eosinophilia, and atopy (asthma). ACO patients have more exacerbations and worse outcomes. The key treatment difference: ACO requires ICS as part of therapy."},{question:"Why is ICS essential in ACO but not always in COPD?",answer:"ACO has an eosinophilic/Type 2 inflammatory component that responds to corticosteroids. Without ICS, this inflammation goes untreated, leading to more exacerbations and faster decline. Pure COPD without eosinophilia may not benefit from ICS."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"neonatal-cpap",title:"Neonatal CPAP Therapy",category:"Neonatal/Pediatric Respiratory Care",seoTitle:"Neonatal CPAP – Bubble CPAP, Nasal Prongs & Indications | RRT",seoDescription:"Learn neonatal CPAP: bubble CPAP, nasal prong selection, indications for preterm RDS, and weaning criteria for the RRT exam.",seoKeywords:["neonatal CPAP","bubble CPAP","nasal prongs","preterm RDS","COIN trial","RRT exam"],overview:"Nasal CPAP is a primary respiratory support modality for preterm infants, providing continuous distending pressure to maintain FRC, prevent alveolar collapse, and reduce the need for mechanical ventilation. The COIN trial and SUPPORT trial established early CPAP as an alternative to intubation and surfactant for moderately preterm infants with RDS.",mechanismPhysiology:"CPAP provides a continuous distending pressure (typically 5–8 cmH2O) that: (1) maintains alveolar patency and prevents atelectasis, (2) increases FRC, improving V/Q matching, (3) reduces work of breathing by splinting the compliant neonatal chest wall, (4) stabilizes the upper airway (reducing obstructive apnea), (5) conserves surfactant by preventing alveolar collapse. Delivery methods: bubble CPAP (underwater seal creates oscillating pressure — may enhance gas exchange), ventilator-derived CPAP, or infant flow driver (variable flow).",clinicalRelevance:"SUPPORT trial: early CPAP (starting in delivery room) vs intubation/surfactant in infants 24–27 weeks — CPAP group had similar mortality/BPD but less surfactant use and fewer ventilator days. Current approach: initial CPAP for spontaneously breathing preterm infants, with rescue surfactant (INSURE or LISA) if FiO2 rises above threshold (typically > 0.30–0.40). Bubble CPAP is the most widely used delivery method globally and may provide additional benefit from pressure oscillations.",signsSymptoms:"Indications: RDS in preterm infants, apnea of prematurity, post-extubation support, transient tachypnea of the newborn, meconium aspiration (mild), bronchiolitis. Signs of CPAP failure requiring escalation: FiO2 > 0.40, persistent apnea, worsening respiratory distress, pH < 7.20, PaCO2 > 65.",assessment:"Monitor: FiO2 requirement, respiratory effort, chest expansion, SpO2, nasal interface fit, abdominal distension (aerophagia), skin integrity at interface contact points. CXR: assess lung expansion (optimal 7–8 rib levels on CPAP).",management:"Start CPAP 5–6 cmH2O via binasal prongs or nasal mask. Increase to 7–8 cmH2O if needed. Interface selection: short binasal prongs (most evidence), nasal mask (alternative — may reduce nasal injury). Proper sizing is critical to prevent nasal trauma. Bubble CPAP: water level in the expiratory limb determines CPAP level. Weaning: reduce CPAP pressure gradually (6 → 5 → 4), then transition to low-flow nasal cannula.",complications:"Nasal injury (septal erosion, columella necrosis — most common complication), abdominal distension from aerophagia (place OG tube for decompression), pneumothorax (rare at appropriate pressures), nasal obstruction from secretions.",clinicalPearls:["Short binasal prongs have the most evidence — proper sizing reduces nasal injury","Place an OG tube for gastric decompression during CPAP — prevents abdominal distension from aerophagia","Bubble CPAP is simple, effective, and may provide additional gas exchange benefit from oscillations","CPAP failure threshold: FiO2 > 0.30–0.40 suggests need for surfactant (INSURE/LISA)"],examPitfalls:["Not recognizing nasal injury as the most common CPAP complication in neonates","Setting CPAP pressure too high (> 8 cmH2O) — increases pneumothorax risk","Not placing an OG tube for gastric decompression during neonatal CPAP","Forgetting that bubble CPAP level is determined by the water depth in the expiratory limb"],faqJson:[{question:"What is bubble CPAP?",answer:"The expiratory limb of the CPAP circuit is submerged in water to a specific depth (e.g., 5 cm = 5 cmH2O CPAP). Exhaled gas bubbles through the water, creating a constant pressure. The bubbling creates small pressure oscillations that may enhance gas exchange."},{question:"When should CPAP be escalated to mechanical ventilation?",answer:"When FiO2 exceeds 0.40 despite adequate CPAP (indicating surfactant need or disease progression), persistent or severe apnea, worsening acidosis (pH < 7.20), or PaCO2 > 65 mmHg despite maximum CPAP."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"asthma-action-plan",title:"Asthma Action Plans",category:"Asthma",seoTitle:"Asthma Action Plans – Green, Yellow, Red Zone Management | RRT",seoDescription:"Learn asthma action plans: zone-based self-management, peak flow monitoring, and medication adjustment for the RRT exam.",seoKeywords:["asthma action plan","green yellow red zone","peak flow","self-management","asthma education","RRT exam"],overview:"Written asthma action plans are individualized self-management tools that guide patients in daily management, early recognition of worsening symptoms, and appropriate response to exacerbations. The traffic light system (green/yellow/red zones) uses symptoms and peak flow measurements to direct medication adjustments and when to seek emergency care.",mechanismPhysiology:"Action plans are based on peak expiratory flow (PEF) or symptom assessment. Personal best PEF is determined during a 2–3 week period of optimal control. Green zone: PEF 80–100% personal best (well-controlled — continue maintenance therapy). Yellow zone: PEF 50–80% (caution — increase medications, add rescue therapy). Red zone: PEF < 50% (medical alert — use rescue medications and seek immediate medical care). Zones correspond to airflow limitation severity and guide stepwise intensification.",clinicalRelevance:"Studies show written action plans reduce ER visits by 30–40% and hospitalizations by 50%. Elements: daily controller medications, rescue medication instructions, zone-based adjustments, and emergency contact information. Peak flow monitoring is especially useful for patients with poor symptom perception ('poor perceivers' who don't recognize worsening until severe). RT role: educate patients on PEF technique, action plan use, and inhaler technique.",signsSymptoms:"Green zone: no cough, wheeze, chest tightness, or SOB; sleeps through the night; can do usual activities; PEF 80–100% personal best. Yellow zone: cough, wheeze, chest tightness, or SOB; nighttime awakening; limitation of some activities; PEF 50–80%. Red zone: very short of breath; rescue meds not helping; cannot do usual activities; lips/fingernails blue; PEF < 50%.",assessment:"Determine personal best PEF over 2–3 weeks of good control. Calculate zone values: green ≥ 80%, yellow 50–80%, red < 50% of personal best. Assess understanding of the plan at each visit. Review peak flow diary and symptom patterns. Evaluate inhaler technique.",management:"Green zone: continue daily controller therapy, use SABA PRN before exercise. Yellow zone: increase controller dose (double ICS or add LABA), use SABA every 4–6 hours, call provider if no improvement in 24–48 hours. Red zone: take SABA immediately (4–6 puffs), start oral corticosteroid burst (prednisone 40–60 mg), seek emergency care immediately, call 911 if no improvement or worsening.",complications:"Non-adherence to action plan, failure to recognize worsening (poor perceivers), delayed emergency care, improper PEF technique giving inaccurate readings.",clinicalPearls:["Written action plans reduce ER visits by 30–40% — ensure every asthma patient has one","Personal best PEF should be updated annually or after medication changes","Some patients are 'poor perceivers' — they don't recognize worsening until PEF is critically low; PEF monitoring is especially important for them","Review the action plan at every clinic visit and after every exacerbation"],examPitfalls:["Not knowing the zone cutoffs: green ≥ 80%, yellow 50–80%, red < 50% of personal best","Forgetting to include oral corticosteroid burst in the red zone instructions","Using predicted PEF instead of personal best PEF for zone calculations","Not providing a written action plan to every asthma patient"],faqJson:[{question:"What is the personal best PEF?",answer:"The highest PEF achieved during a 2–3 week period when asthma is well-controlled. It is used as the reference value for calculating green (≥ 80%), yellow (50–80%), and red (< 50%) zones in the asthma action plan."},{question:"Why are written action plans important?",answer:"Written plans reduce ER visits by 30–40% and hospitalizations by 50%. They empower patients to recognize early worsening and take appropriate action before a severe exacerbation develops."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"status-asthmaticus",title:"Status Asthmaticus",category:"Asthma",seoTitle:"Status Asthmaticus – Severe Acute Asthma Management | RRT",seoDescription:"Learn status asthmaticus: recognition, aggressive bronchodilator therapy, IV magnesium, intubation considerations, and ICU management for the RRT exam.",seoKeywords:["status asthmaticus","severe asthma","acute asthma","continuous nebulization","IV magnesium","intubation asthma","RRT exam"],overview:"Status asthmaticus is a severe, life-threatening asthma exacerbation that does not respond to standard bronchodilator therapy. It represents the most critical asthma emergency, requiring aggressive treatment with continuous nebulized albuterol, systemic corticosteroids, IV magnesium, and potentially mechanical ventilation. Mortality approaches 10% in intubated asthma patients.",mechanismPhysiology:"Severe bronchospasm + airway inflammation + mucus plugging → critical airflow obstruction → severe air trapping and hyperinflation → increased work of breathing → respiratory muscle fatigue → respiratory failure. The 'silent chest' represents the most severe stage — airflow is so limited that wheezing disappears. Progressive hyperinflation increases intrathoracic pressure, reducing venous return and cardiac output. Severe metabolic acidosis develops from respiratory muscle lactate production and tissue hypoperfusion.",clinicalRelevance:"Recognition of impending respiratory failure: 'silent chest,' inability to speak, diaphoresis, altered consciousness, paradoxical breathing, PaCO2 rising above normal (in asthma, PaCO2 should be LOW from hyperventilation — a 'normal' PaCO2 of 40 in severe asthma indicates impending failure). Aggressive bronchodilator therapy: continuous nebulized albuterol (10–15 mg/hour) + ipratropium q20min × 3. Systemic steroids immediately (methylprednisolone 125 mg IV). IV magnesium sulfate 2g over 20 minutes.",signsSymptoms:"Severe: speaks in single words, sits upright and forward, agitated, RR > 30, HR > 120, SpO2 < 90%, PEF < 25% predicted. Life-threatening: silent chest, cyanosis, bradycardia (ominous), drowsiness/confusion, inability to speak, PEF unmeasurable, PaCO2 rising. Near-fatal: requires intubation with mechanical ventilation, respiratory acidosis.",assessment:"Assess severity rapidly: ability to speak (sentences → phrases → words → none), respiratory rate, heart rate, SpO2, mental status, accessory muscle use. ABG: initial respiratory alkalosis (compensatory hyperventilation) → normalization of PaCO2 (ominous — muscles fatiguing) → respiratory acidosis (imminent arrest). PEF if patient able: < 25% predicted = severe.",management:"Continuous albuterol nebulization 10–15 mg/hour. Ipratropium 0.5 mg q20min × 3 doses then q2–4h. Methylprednisolone 125 mg IV (or equivalent). IV magnesium sulfate 2g over 20 minutes (smooth muscle relaxation). Heliox (70:30 or 80:20) if available — reduces airway resistance. Epinephrine 0.3 mg IM (if no response to nebulized therapy or unable to inhale). If intubation required: ketamine for induction (bronchodilator properties), slow RR (8–12), prolonged expiratory time (I:E 1:4 or 1:5), low PEEP (≤ 5), permissive hypercapnia, tolerate low Vt.",complications:"Respiratory arrest, pneumothorax (air trapping → alveolar rupture), cardiac arrest (hypoxia, acidosis), ICU-acquired weakness (high-dose steroids), myopathy, death. Intubated asthmatics: extremely difficult to ventilate due to severe obstruction and air trapping.",clinicalPearls:["A 'normal' PaCO2 (40 mmHg) in acute asthma is OMINOUS — it indicates respiratory muscle fatigue","The 'silent chest' is the most dangerous sign — it means virtually no airflow, not improvement","If intubation is needed: use low RR (8–12), prolonged expiratory time (I:E 1:4–1:5), and expect severe auto-PEEP","IV magnesium is effective as an adjunct — give 2g IV over 20 minutes for severe exacerbations"],examPitfalls:["Interpreting a 'normal' PaCO2 as reassuring in acute asthma — it indicates impending failure","Thinking a 'silent chest' means the patient is improving","Not recognizing that intubated asthmatics need very different ventilator settings (low RR, prolonged expiration)","Forgetting IV magnesium as an adjunct therapy in severe exacerbations"],faqJson:[{question:"Why is a normal PaCO2 ominous in acute asthma?",answer:"During an asthma attack, patients hyperventilate (compensatory response to bronchospasm), so PaCO2 should be LOW (< 35 mmHg). A 'normal' PaCO2 of 40 means the patient can no longer compensate — respiratory muscles are fatiguing. Rising PaCO2 indicates imminent respiratory failure."},{question:"Why are ventilator settings different for asthma?",answer:"Severe air trapping in asthma requires prolonged expiratory time to prevent dangerous auto-PEEP. Settings: low RR (8–12), short inspiratory time, prolonged I:E ratio (1:4 or 1:5), minimal PEEP, accept permissive hypercapnia. Standard settings risk fatal auto-PEEP and cardiovascular collapse."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"respiratory-failure-types",title:"Types of Respiratory Failure",category:"Patient Assessment",seoTitle:"Respiratory Failure Types – Type I, II, III, IV Classification | RRT",seoDescription:"Learn respiratory failure classification: Type I hypoxemic, Type II hypercapnic, Type III perioperative, and Type IV shock-related for the RRT exam.",seoKeywords:["respiratory failure","type I","type II","hypoxemic","hypercapnic","acute respiratory failure","RRT exam"],overview:"Respiratory failure is classified based on the primary gas exchange abnormality. Type I (hypoxemic): PaO2 < 60 mmHg on room air with normal or low PaCO2 — failure of oxygenation. Type II (hypercapnic): PaCO2 > 50 mmHg with respiratory acidosis — failure of ventilation. Type III (perioperative): atelectasis-related. Type IV (shock-related): hypoperfusion causing respiratory muscle failure. Understanding the type guides treatment strategy.",mechanismPhysiology:"Type I: V/Q mismatch, shunt, diffusion impairment, or low FiO2 cause hypoxemia without CO2 retention. The lung can still ventilate but cannot oxygenate. Causes: pneumonia, ARDS, pulmonary edema, PE. Type II: inadequate alveolar ventilation causes CO2 accumulation. Causes: COPD, neuromuscular disease, drug overdose, chest wall disorders. Can be acute (acidotic) or chronic (compensated). Type III: post-operative atelectasis from anesthesia, splinting, and supine positioning. Type IV: respiratory muscle failure from inadequate perfusion in shock — muscles cannot meet the metabolic demand of breathing.",clinicalRelevance:"Type I: treat underlying cause + supplemental O2 (responds to O2 unless pure shunt — shunt is refractory to O2). Type II: improve ventilation (NIV for COPD exacerbation, reversal agents for overdose, mechanical ventilation for neuromuscular failure). Mixed Type I+II: common in severe disease (COPD with pneumonia). Important: Type II can be acute (pH < 7.35) or chronic (pH normal with elevated HCO3 compensation).",signsSymptoms:"Type I: tachypnea, dyspnea, cyanosis, restlessness, tachycardia, hypoxemia with SpO2 < 90%. Type II: headache, somnolence, confusion (CO2 narcosis), asterixis, papilledema, warm flushed skin, bounding pulses. Combined: features of both. Type IV: signs of shock plus respiratory distress.",assessment:"ABG is essential: Type I — PaO2 < 60 with PaCO2 ≤ 40 (or low). Type II — PaCO2 > 50 with pH indicating acute (< 7.35) vs chronic (normal pH, elevated HCO3). Calculate A-a gradient: elevated in Type I (V/Q mismatch, shunt, diffusion), normal in Type II (hypoventilation with normal lungs). Assess underlying cause with imaging, labs, and clinical context.",management:"Type I: supplemental O2, treat underlying cause (antibiotics for pneumonia, diuretics for edema), consider HFNC/NIV/intubation based on severity. Type II acute: NIV for COPD (strongest indication), naloxone for opioid overdose, mechanical ventilation for neuromuscular failure. Type II chronic: avoid over-oxygenation (target SpO2 88–92%), treat exacerbation triggers. Type IV: treat shock, support ventilation, intubate early (reduce respiratory muscle O2 consumption).",complications:"Cardiopulmonary arrest if untreated, multi-organ dysfunction from prolonged hypoxemia, complications of mechanical ventilation (VILI, VAP), long-term cognitive impairment in survivors.",clinicalPearls:["A normal A-a gradient with hypercapnia suggests pure hypoventilation — the lungs themselves are normal","Type I that does NOT respond to supplemental O2 suggests intrapulmonary SHUNT (ARDS, large pneumonia)","Acute-on-chronic Type II is common in COPD — look for elevated HCO3 with acute pH drop","Type IV respiratory failure in shock: intubation reduces respiratory muscle O2 consumption by 30–50%"],examPitfalls:["Not distinguishing Type I from Type II — treatment strategies are fundamentally different","Forgetting to calculate A-a gradient — it helps localize the problem","Not recognizing acute-on-chronic respiratory failure (new acidosis in a chronically compensated patient)","Over-oxygenating a Type II patient (COPD) — worsening hypercapnia"],faqJson:[{question:"What is the A-a gradient and how does it help?",answer:"A-a gradient = PAO2 − PaO2. Normal < 10–15 mmHg (increases with age). An elevated A-a gradient indicates a lung problem (V/Q mismatch, shunt, diffusion impairment). A normal A-a gradient with hypercapnia indicates pure hypoventilation with normal lungs (drug overdose, neuromuscular disease)."},{question:"Why does pure shunt not respond to supplemental O2?",answer:"In shunt, blood passes through completely non-ventilated lung units (consolidated or collapsed alveoli). No matter how much O2 is delivered to ventilated alveoli, the shunted blood bypasses them entirely and remains deoxygenated, mixing with oxygenated blood and lowering PaO2."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"airway-clearance-techniques",title:"Airway Clearance Techniques",category:"Pulmonary Rehabilitation",seoTitle:"Airway Clearance – CPT, PEP, OPEP, Autogenic Drainage | RRT",seoDescription:"Master airway clearance techniques: CPT, postural drainage, PEP therapy, OPEP devices, HFCWO, and autogenic drainage for the RRT exam.",seoKeywords:["airway clearance","CPT","postural drainage","PEP","OPEP","Acapella","Flutter","vest therapy","RRT exam"],overview:"Airway clearance techniques (ACTs) mobilize and remove retained secretions from the airways. They are essential in cystic fibrosis, bronchiectasis, and other conditions with impaired mucociliary clearance. Techniques include chest physiotherapy (CPT) with postural drainage, positive expiratory pressure (PEP), oscillating PEP (OPEP), high-frequency chest wall oscillation (HFCWO/vest therapy), active cycle of breathing, and autogenic drainage.",mechanismPhysiology:"CPT: percussion and vibration transmit energy waves through the chest wall to loosen secretions from airway walls. Postural drainage uses gravity to drain secretions from specific lung segments into central airways for removal by cough. PEP: exhaling against resistance (10–20 cmH2O) splints airways open, ventilates behind mucus plugs via collateral channels (pores of Kohn, canals of Lambert), and moves secretions toward central airways. OPEP (Flutter, Acapella): combines PEP with oscillating pressure waves that vibrate airway walls, shearing mucus loose. HFCWO (vest): external chest wall oscillations at 5–25 Hz create small pulsatile airflows that mobilize secretions.",clinicalRelevance:"CF guidelines recommend daily airway clearance for all patients. No single technique is clearly superior — patient preference and adherence drive selection. PEP and OPEP devices are preferred for independence and portability. CPT with postural drainage remains effective, especially in young children and those unable to perform active techniques. HFCWO (vest therapy) provides hands-free treatment but requires equipment and is costly. Active cycle of breathing and autogenic drainage are physiotherapy-guided techniques requiring patient cooperation.",signsSymptoms:"Indications: cystic fibrosis (all patients), bronchiectasis, retained secretions in acute illness (pneumonia, post-operative), neuromuscular disease with weak cough, chronic bronchitis with mucus hypersecretion. Effectiveness indicators: increased sputum production, improved breath sounds, improved SpO2, reduced dyspnea.",assessment:"Assess before and after treatment: auscultation (rhonchi should decrease), sputum volume/character, SpO2, respiratory rate, patient tolerance. Monitor for adverse effects: desaturation during treatment, hemoptysis, rib fractures (osteoporotic patients), bronchospasm, increased ICP.",management:"CPT: position patient in appropriate drainage position for affected segments, percussion for 3–5 minutes per position, vibration during exhalation, followed by coughing/huffing. PEP: 10–15 breaths through PEP device (10–20 cmH2O), followed by 2–3 huff coughs, repeat 4–6 cycles. OPEP: similar to PEP but device provides oscillation. Pre-treat with bronchodilator 15–30 minutes before ACT. Best performed before meals (reduce nausea/vomiting risk) or 1–2 hours after meals.",complications:"Desaturation during treatment, hemoptysis exacerbation, rib fractures (osteoporosis), increased ICP (Trendelenburg positioning), aspiration (if positioned head-down after meals), bronchospasm, fatigue.",clinicalPearls:["No single airway clearance technique is clearly superior — PATIENT PREFERENCE drives adherence","PEP and OPEP devices are preferred for independence — the patient can do therapy without assistance","Pre-treat with bronchodilator 15–30 minutes before airway clearance","Trendelenburg positioning is CONTRAINDICATED in: increased ICP, uncontrolled HTN, recent esophageal/gastric surgery, hemoptysis"],examPitfalls:["Placing a patient in Trendelenburg position when contraindicated (increased ICP, hemoptysis, uncontrolled HTN)","Not pre-treating with bronchodilator before airway clearance","Thinking one technique is clearly superior to all others","Performing CPT immediately after meals"],faqJson:[{question:"What is the difference between PEP and OPEP?",answer:"PEP provides constant positive expiratory pressure only. OPEP (Flutter valve, Acapella) provides PEP PLUS oscillating pressure waves that vibrate the airway walls, creating shearing forces that help loosen mucus from the airway wall in addition to splinting airways open."},{question:"When should airway clearance be performed relative to meals?",answer:"Airway clearance should be performed before meals or at least 1–2 hours after meals. Postural drainage positions (especially Trendelenburg) after eating can cause nausea, vomiting, and aspiration risk."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"pulmonary-hypertension",title:"Pulmonary Hypertension for Respiratory Therapists",category:"Critical Care",seoTitle:"Pulmonary Hypertension – Classification & Respiratory Management | RRT",seoDescription:"Learn pulmonary hypertension: WHO classification, hemodynamic diagnosis, inhaled nitric oxide, and respiratory management for the RRT exam.",seoKeywords:["pulmonary hypertension","PH","pulmonary arterial hypertension","PAH","inhaled nitric oxide","iNO","RRT exam"],overview:"Pulmonary hypertension (PH) is defined as mean pulmonary arterial pressure (mPAP) > 20 mmHg at rest by right heart catheterization. The WHO classifies PH into 5 groups based on etiology. Respiratory therapists manage patients with PH through oxygen therapy, inhaled nitric oxide (iNO), inhaled prostacyclins, and mechanical ventilation optimization to minimize RV afterload.",mechanismPhysiology:"WHO Group 1 (PAH): primary pulmonary vascular disease — endothelial dysfunction, smooth muscle proliferation, in-situ thrombosis → progressive increase in pulmonary vascular resistance (PVR) → RV failure. Group 2: left heart disease. Group 3: lung disease/hypoxia (COPD, ILD — chronic hypoxic vasoconstriction). Group 4: chronic thromboembolic (CTEPH). Group 5: multifactorial. Hemodynamic criteria: precapillary PH (Group 1,3,4): mPAP > 20, PCWP ≤ 15, PVR > 2 WU. Postcapillary (Group 2): mPAP > 20, PCWP > 15.",clinicalRelevance:"RT-relevant management: supplemental O2 to prevent hypoxic vasoconstriction (target SpO2 > 90%). Inhaled nitric oxide (iNO): selective pulmonary vasodilator, 5–40 ppm. Used in: acute PH crisis, RV failure, PPHN in neonates, testing vasoreactivity. Inhaled epoprostenol/iloprost: nebulized pulmonary vasodilators. Mechanical ventilation in PH: minimize PEEP (increases RV afterload), avoid hypoxia and hypercapnia (both increase PVR), avoid high tidal volumes.",signsSymptoms:"Dyspnea on exertion (most common), fatigue, chest pain, syncope (ominous — indicates severely limited CO), peripheral edema, JVD, loud P2, RV heave, tricuspid regurgitation murmur, hepatomegaly.",assessment:"6MWT (functional assessment), echocardiography (RV dilation, TR jet velocity for estimating PASP), right heart catheterization (gold standard — mPAP, PCWP, CO, PVR), BNP/NT-proBNP (RV strain marker). Vasoreactivity testing with iNO: positive response (mPAP falls > 10 to < 40 mmHg with improved CO) predicts calcium channel blocker response.",management:"Oxygen to prevent hypoxic vasoconstriction. iNO 5–40 ppm for acute PH crisis (monitor methemoglobin, must wean slowly — avoid rebound PH). Inhaled prostacyclins (epoprostenol, iloprost) as nebulized pulmonary vasodilators. Ventilator management: minimize mean airway pressure, avoid overdistension (increases PVR), optimal PEEP (too much or too little increases PVR), avoid acidosis and hypoxia.",complications:"RV failure (leading cause of death), rebound PH from abrupt iNO discontinuation, methemoglobinemia from iNO, hemodynamic collapse with induction of anesthesia or positive pressure ventilation.",clinicalPearls:["iNO must be weaned gradually — abrupt discontinuation causes rebound pulmonary hypertension","iNO is a SELECTIVE pulmonary vasodilator — it only reaches ventilated lung units, improving V/Q matching without systemic hypotension","Avoid excessive PEEP in PH patients — it increases RV afterload","Monitor methemoglobin levels during iNO therapy — target < 5%"],examPitfalls:["Abruptly discontinuing iNO — causes rebound PH","Applying high PEEP to patients with RV failure/PH — worsens hemodynamics","Not knowing that iNO is selective to ventilated lung units (systemic vasodilators are NOT selective)","Forgetting to monitor methemoglobin during iNO administration"],faqJson:[{question:"Why is inhaled nitric oxide selective to the pulmonary vasculature?",answer:"iNO is delivered via inhalation and only reaches ventilated alveoli, where it diffuses into adjacent pulmonary capillary smooth muscle, causing vasodilation. It is immediately inactivated by hemoglobin in the blood, so it has no systemic vasodilatory effect."},{question:"Why does iNO need to be weaned slowly?",answer:"The pulmonary vasculature becomes dependent on exogenous NO during prolonged use. Abrupt discontinuation removes this vasodilatory stimulus, causing acute rebound pulmonary vasoconstriction and potentially life-threatening pulmonary hypertension crisis."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"sleep-disordered-breathing-screening",title:"Sleep-Disordered Breathing Screening",category:"Sleep Medicine",seoTitle:"Sleep Apnea Screening – STOP-BANG, Epworth & Risk Assessment | RRT",seoDescription:"Learn sleep-disordered breathing screening: STOP-BANG questionnaire, Epworth Sleepiness Scale, risk factors, and referral criteria for the RRT exam.",seoKeywords:["sleep apnea screening","STOP-BANG","Epworth Sleepiness Scale","OSA risk factors","sleep screening","RRT exam"],overview:"Sleep-disordered breathing (SDB) screening identifies patients at risk for obstructive sleep apnea (OSA) and other sleep disorders. OSA affects 10–30% of adults but is undiagnosed in 80% of cases. Validated screening tools include the STOP-BANG questionnaire, Epworth Sleepiness Scale (ESS), and Berlin Questionnaire. Respiratory therapists play a key role in identifying at-risk patients during routine assessments.",mechanismPhysiology:"OSA results from upper airway collapse during sleep due to: reduced pharyngeal muscle tone (sleep-related), anatomical narrowing (obesity, retrognathia, enlarged tonsils, macroglossia), and inadequate neural drive to pharyngeal dilator muscles. Risk factors: obesity (BMI > 35), male sex, age > 50, neck circumference > 40 cm, craniofacial abnormalities, family history, alcohol/sedative use, smoking. OSA causes intermittent hypoxemia, sympathetic activation, and sleep fragmentation.",clinicalRelevance:"STOP-BANG: Snoring, Tiredness, Observed apneas, high blood Pressure, BMI > 35, Age > 50, Neck circumference > 40 cm, Gender (male). Score ≥ 3 = intermediate risk, ≥ 5 = high risk for moderate-severe OSA. Sensitivity > 90% for moderate-severe OSA at score ≥ 3. ESS: 8-question subjective sleepiness scale (0–24). Score > 10 = excessive daytime sleepiness. Perioperative screening is particularly important — undiagnosed OSA increases surgical complication risk.",signsSymptoms:"Classic symptoms: loud snoring, witnessed apneas, excessive daytime sleepiness, unrefreshing sleep, morning headaches, nocturia, dry mouth on waking. Associated conditions: resistant hypertension, atrial fibrillation, type 2 diabetes, obesity, stroke, heart failure, pulmonary hypertension.",assessment:"Screen using STOP-BANG at hospital admission, preoperative clinic, and pulmonary clinic visits. Assess Epworth Sleepiness Scale for subjective sleepiness. Review comorbidities suggestive of OSA (resistant hypertension, A-fib, type 2 DM). If positive screen: refer for PSG or HSAT. Perioperative: screen all patients before procedures requiring sedation/anesthesia.",management:"Positive screen (STOP-BANG ≥ 3): refer for diagnostic testing (HSAT for uncomplicated OSA, PSG for comorbid patients). While awaiting diagnosis: lateral sleeping position, avoid alcohol/sedatives before bed, weight loss counseling. Perioperative considerations for suspected OSA: avoid excessive sedation, continuous SpO2 monitoring post-operatively, semi-upright positioning, consider CPAP if already prescribed.",complications:"Undiagnosed OSA: cardiovascular events (MI, stroke, arrhythmias), motor vehicle accidents (2–7× increased risk), perioperative complications (difficult intubation, post-operative respiratory failure), cognitive impairment, depression.",clinicalPearls:["STOP-BANG ≥ 3 has > 90% sensitivity for moderate-severe OSA — it rarely misses significant disease","ESS > 10 indicates excessive daytime sleepiness but is SUBJECTIVE — some severe OSA patients deny sleepiness","Screen ALL patients before procedures requiring sedation — undiagnosed OSA increases perioperative risk","80% of OSA is UNDIAGNOSED — respiratory therapists should actively screen during routine encounters"],examPitfalls:["Not knowing the STOP-BANG components and scoring","Thinking a normal ESS rules out OSA — some patients underreport sleepiness","Not screening perioperative patients for OSA risk","Confusing screening tools (STOP-BANG, ESS, Berlin) — know which measures what"],faqJson:[{question:"What is STOP-BANG and how is it scored?",answer:"STOP-BANG: Snoring, Tiredness, Observed apneas, high blood Pressure, BMI > 35, Age > 50, Neck > 40 cm, Gender (male). One point per 'yes.' Score 0–2 = low risk, 3–4 = intermediate risk, 5–8 = high risk for moderate-severe OSA."},{question:"Why is perioperative OSA screening important?",answer:"Undiagnosed OSA increases risk of: difficult intubation (airway anatomy), post-operative respiratory depression (sedation sensitivity), desaturation events, ICU admission, cardiac arrhythmias, and longer hospital stay. Early identification allows appropriate precautions."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"persistent-pulmonary-hypertension-newborn",title:"Persistent Pulmonary Hypertension of the Newborn (PPHN)",category:"Neonatal/Pediatric Respiratory Care",seoTitle:"PPHN – Persistent Pulmonary Hypertension of the Newborn | RRT",seoDescription:"Learn PPHN: pathophysiology, right-to-left shunting, inhaled nitric oxide, and management strategies for the RRT exam.",seoKeywords:["PPHN","persistent pulmonary hypertension","newborn","inhaled nitric oxide","iNO","right-to-left shunt","RRT exam"],overview:"Persistent pulmonary hypertension of the newborn (PPHN) occurs when pulmonary vascular resistance (PVR) fails to decrease after birth, maintaining fetal circulation patterns with right-to-left shunting through the patent foramen ovale (PFO) and patent ductus arteriosus (PDA). This causes severe hypoxemia refractory to supplemental oxygen. PPHN affects 1–2 per 1,000 live births.",mechanismPhysiology:"Normal transition at birth: first breaths expand the lungs → alveolar PO2 rises → pulmonary vasoconstriction reverses → PVR drops → PBF increases → left atrial pressure rises → PFO closes functionally → PDA constricts. In PPHN: PVR remains elevated → right-to-left shunting through PFO and PDA → deoxygenated blood enters systemic circulation → severe hypoxemia. Causes: idiopathic, meconium aspiration syndrome (most common), sepsis/pneumonia, RDS, congenital diaphragmatic hernia, pulmonary hypoplasia.",clinicalRelevance:"Hallmark: pre-ductal (right hand) SpO2 > post-ductal (foot) SpO2 by ≥ 5–10% — confirms right-to-left ductal shunting. However, PFO shunting alone may show equal pre/post-ductal saturations. Echocardiography confirms diagnosis: tricuspid regurgitation jet, flat/bowing of interventricular septum, right-to-left or bidirectional shunting at PFO/PDA. iNO (inhaled nitric oxide) at 20 ppm is the primary pharmacological therapy — selective pulmonary vasodilator.",signsSymptoms:"Severe cyanosis within hours of birth, tachypnea, respiratory distress, labile oxygenation (SpO2 fluctuates with handling/stress), pre-post ductal saturation difference ≥ 5–10%, loud single S2 (no splitting), systolic murmur of TR.",assessment:"Pre-ductal (right hand) vs post-ductal (foot) SpO2: difference ≥ 5–10% suggests right-to-left ductal shunting. Echocardiography: elevated PASP estimate, TR jet, septal bowing, shunt direction at PFO/PDA, rule out congenital heart disease. Hyperoxia test: failure of PaO2 to rise above 100 mmHg on 100% FiO2 suggests PPHN or cyanotic heart disease.",management:"General: minimize stimulation and handling (stress worsens PH), optimize oxygenation (FiO2 to target SpO2 > 95% pre-ductal), correct acidosis/hypothermia/hypoglycemia. iNO: 20 ppm — improvement in PaO2 > 20 mmHg within 30–60 minutes indicates response. Mechanical ventilation: optimize lung recruitment (atelectasis worsens PVR) but avoid overdistension. Sedation (fentanyl, morphine) to reduce agitation. ECMO: for refractory PPHN (OI > 40 despite maximal therapy).",complications:"Rebound PH from abrupt iNO discontinuation, methemoglobinemia from iNO, need for ECMO (10–15% of PPHN), neurodevelopmental impairment, hearing loss, chronic lung disease in survivors.",clinicalPearls:["Pre-post ductal saturation difference ≥ 5% is the bedside hallmark of PPHN — check on every cyanotic newborn","Minimize handling and stimulation — stress increases PVR and worsens shunting","iNO must be weaned gradually (never abruptly discontinue) — start at 20 ppm, wean by 5 ppm to 5 ppm, then by 1 ppm","PPHN is a diagnosis of EXCLUSION — must rule out cyanotic congenital heart disease with echocardiography"],examPitfalls:["Not checking pre-post ductal saturations in a cyanotic newborn","Confusing PPHN with cyanotic congenital heart disease — echo is essential","Abruptly discontinuing iNO — causes rebound PH","Stimulating and handling the infant excessively — this worsens PVR and shunting"],faqJson:[{question:"How does iNO treat PPHN?",answer:"iNO selectively dilates pulmonary blood vessels in ventilated lung areas, reducing PVR and improving V/Q matching. It is immediately inactivated by hemoglobin, so it does not cause systemic hypotension. Starting dose is 20 ppm."},{question:"What is the significance of pre-post ductal saturation difference?",answer:"Pre-ductal (right hand) SpO2 reflects blood BEFORE the ductus arteriosus. Post-ductal (foot) SpO2 reflects blood AFTER the ductus. A difference ≥ 5–10% indicates right-to-left shunting through the PDA, confirming that PVR exceeds systemic vascular resistance — consistent with PPHN."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"helium-oxygen-therapy",title:"Helium-Oxygen (Heliox) Therapy",category:"Oxygen Therapy",seoTitle:"Heliox Therapy – Helium-Oxygen for Airway Obstruction | RRT",seoDescription:"Learn heliox therapy: physics of gas density, clinical applications for stridor and asthma, limitations, and delivery methods for the RRT exam.",seoKeywords:["heliox","helium oxygen","gas density","airway obstruction","stridor","laminar flow","RRT exam"],overview:"Heliox is a mixture of helium and oxygen used to reduce the work of breathing in upper and large airway obstruction. Helium is less dense than nitrogen (1/7 the density), reducing turbulent airflow resistance. Standard mixtures: 80:20 (80% He, 20% O2) and 70:30 (70% He, 30% O2). The lower the helium concentration, the less benefit — mixtures below 60% helium provide minimal advantage.",mechanismPhysiology:"Airway resistance in turbulent flow is proportional to gas density (Reynolds number). Turbulent flow occurs in the upper airways, trachea, and large bronchi — areas of high velocity and branching. By replacing nitrogen (density 1.25 g/L) with helium (density 0.18 g/L), the gas mixture density decreases significantly, converting turbulent flow to laminar flow. Laminar flow resistance is independent of gas density (depends on viscosity), reducing the pressure gradient needed for airflow and decreasing work of breathing. Heliox does NOT affect small airway resistance (already laminar flow) or bronchospasm.",clinicalRelevance:"Most effective in: upper airway obstruction (post-extubation stridor, croup, tracheal tumors, vocal cord dysfunction), large airway obstruction (foreign body, tracheal stenosis). Moderate evidence: severe asthma (bridge while medications take effect), COPD exacerbation. Less effective: small airway disease (asthma, COPD) because turbulence is primarily in large airways. Heliox is a TEMPORIZING measure — it does not treat the underlying condition.",signsSymptoms:"Clinical improvement indicators: decreased stridor, reduced work of breathing, improved air entry on auscultation, decreased respiratory rate, improved patient comfort. Limited benefit indicators: no change in WOB, persistent hypoxemia requiring FiO2 > 0.40 (heliox concentration too low to be effective).",assessment:"Assess severity of obstruction before starting. Monitor respiratory rate, work of breathing, SpO2, and auscultation findings before and after initiation. Flow meters are INACCURATE with heliox — actual flow is 1.8× the displayed flow for 80:20 mixture (correction factor needed). Note: oxygen analyzers are accurate with heliox.",management:"Deliver via tight-fitting non-rebreather mask or through ventilator with heliox-capable software. Start with 80:20 (maximum benefit). If FiO2 > 0.40 needed: effectiveness decreases (less helium in the mixture). Cannot use standard flow meters — apply correction factor (1.8× for 80:20). Nebulizers: heliox can drive nebulizers but produces smaller particle size — may need to increase nebulization time. Duration: use as bridge to definitive treatment.",complications:"Hypothermia risk (helium has high thermal conductivity — cools airways rapidly), inaccurate flow meter readings, inaccurate tidal volume measurements on ventilators not calibrated for heliox, inability to deliver high FiO2 simultaneously (trade-off between helium concentration and FiO2).",clinicalPearls:["Heliox works best in LARGE airway obstruction — it reduces TURBULENT flow resistance","The benefit decreases as helium percentage drops — below 60% helium, benefit is minimal","Flow meters read INCORRECTLY with heliox — multiply displayed flow by 1.8 for 80:20 mixture","Heliox is a BRIDGE, not a treatment — use it to buy time while definitive therapy takes effect"],examPitfalls:["Thinking heliox is a bronchodilator — it reduces gas density, not bronchospasm","Not applying the flow meter correction factor (1.8× for 80:20)","Using heliox when FiO2 > 0.40 is needed — the helium concentration is too low to be effective","Expecting benefit in pure small airway disease — heliox primarily affects large airway turbulent flow"],faqJson:[{question:"Why does heliox reduce work of breathing?",answer:"Helium is 7× less dense than nitrogen. In areas of turbulent flow (upper airways, trachea, large bronchi), airway resistance is proportional to gas density. By reducing gas density, heliox converts turbulent to laminar flow, decreasing the pressure needed to move gas and reducing work of breathing."},{question:"Why is an 80:20 mixture more effective than 70:30?",answer:"Higher helium concentration = lower gas density = greater reduction in turbulent flow resistance. At 80:20, the mixture is approximately 36% the density of air. At 70:30, it is denser. Below 60% helium, the density reduction is insufficient to provide meaningful clinical benefit."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"oxygen-toxicity",title:"Oxygen Toxicity",category:"Oxygen Therapy",seoTitle:"Oxygen Toxicity – Absorption Atelectasis & Oxidative Injury | RRT",seoDescription:"Learn oxygen toxicity: absorption atelectasis, free radical injury, retinopathy of prematurity, and safe oxygen targets for the RRT exam.",seoKeywords:["oxygen toxicity","absorption atelectasis","free radicals","ROP","hyperoxia","FiO2","RRT exam"],overview:"Oxygen toxicity occurs when supraphysiological oxygen concentrations cause cellular damage through reactive oxygen species (ROS) formation. Two main mechanisms: absorption atelectasis (nitrogen washout at high FiO2 causes alveolar collapse) and direct oxidative injury to pulmonary epithelium (prolonged FiO2 > 0.6). Special populations at risk: premature neonates (retinopathy of prematurity) and post-cardiac arrest patients (hyperoxia worsens neurological outcomes).",mechanismPhysiology:"Absorption atelectasis: nitrogen normally splints alveoli open. At high FiO2, nitrogen is washed out and replaced by O2, which is rapidly absorbed by blood. If the alveolus receives no ventilation (mucus plug, poor collateral ventilation), the O2 is completely absorbed and the alveolus collapses. Oxidative injury: excessive O2 generates reactive oxygen species (superoxide, hydrogen peroxide, hydroxyl radicals) that overwhelm antioxidant defenses → lipid peroxidation, protein denaturation, DNA damage → epithelial cell death, inflammation, and fibrosis. Tracheobronchitis occurs within 24 hours at FiO2 1.0; diffuse alveolar damage within 48–72 hours.",clinicalRelevance:"Guidelines: avoid FiO2 > 0.6 when possible. Target SpO2 92–96% (not 100%) for most adult patients. Premature neonates: target SpO2 91–95% to reduce ROP and BPD risk. Post-cardiac arrest: target SpO2 94–98%, avoid hyperoxia (PaO2 > 300 mmHg associated with worse neurological outcomes). COPD: target SpO2 88–92%. The ICU-ROX trial and LOCO2 trial suggest liberal oxygen may be harmful.",signsSymptoms:"Early: substernal chest pain/burning (tracheobronchitis), cough, dyspnea. Progressive: decreased vital capacity, decreased compliance, worsening A-a gradient (paradoxically — despite high FiO2, lung injury worsens gas exchange). Late: pulmonary edema, ARDS-like picture, fibrosis. Neonatal: ROP (retinal vasoconstriction → ischemia → neovascularization → retinal detachment).",assessment:"Monitor FiO2 exposure: document duration and level. Target lowest FiO2 that achieves desired SpO2. If FiO2 > 0.6 is required for > 24–48 hours, consider strategies to reduce: PEEP optimization, prone positioning, recruitment maneuvers. Monitor neonatal SpO2 targets carefully — avoid SpO2 > 95% in preterm infants.",management:"Prevention: use lowest effective FiO2, optimize PEEP to improve oxygenation at lower FiO2, wean FiO2 before weaning PEEP in ARDS, target appropriate SpO2 ranges for patient population. Treatment: reduce FiO2 if possible, apply PEEP to recruit collapsed alveoli (treating absorption atelectasis), supportive care for established oxidative injury. Neonatal: careful SpO2 targeting, ROP screening.",complications:"Absorption atelectasis, diffuse alveolar damage, pulmonary fibrosis (prolonged exposure), retinopathy of prematurity, worsened neurological outcomes post-cardiac arrest, delayed recognition due to focus on treating hypoxemia.",clinicalPearls:["The GOAL is to use the LOWEST FiO2 that achieves target SpO2 — more O2 is NOT better","Absorption atelectasis is prevented by maintaining some nitrogen in the alveoli — avoid 100% O2 unnecessarily","In ARDS, wean FiO2 BEFORE weaning PEEP — PEEP maintains recruitment while reducing toxic FiO2 exposure","Hyperoxia (PaO2 > 300) post-cardiac arrest is associated with WORSE neurological outcomes"],examPitfalls:["Thinking more oxygen is always better — hyperoxia causes measurable harm","Not knowing the time course: tracheobronchitis within 24 hours, alveolar damage within 48–72 hours at FiO2 1.0","Targeting SpO2 100% in all patients — appropriate targets vary by condition","Forgetting ROP risk in preterm neonates exposed to excessive oxygen"],faqJson:[{question:"What FiO2 level is considered toxic?",answer:"FiO2 > 0.6 (60%) for prolonged periods (> 24–48 hours) is associated with increased risk of oxidative lung injury. FiO2 1.0 (100%) causes detectable tracheobronchitis within 24 hours and diffuse alveolar damage within 48–72 hours. Always use the lowest effective FiO2."},{question:"What is absorption atelectasis?",answer:"At high FiO2, nitrogen (which normally splints alveoli open because it is not absorbed) is washed out and replaced by oxygen. In poorly ventilated alveoli, the oxygen is rapidly absorbed into the blood, and without nitrogen to maintain volume, the alveolus collapses."}],relatedLessonIds:[],relatedQuestionIds:[]}

];
